#!/usr/bin/env bash
# unifi-performance-troubleshoot-l.sh — UniFi performance troubleshoot (low throughput / drop / jitter) SOP walkthrough for UBNT/UniFi 企业 Wi-Fi 工程.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="UBNT/UniFi 企业 Wi-Fi 工程"
WORKFLOW="UniFi performance troubleshoot (low throughput / drop / jitter)"

usage() {
  cat <<EOF
unifi-performance-troubleshoot-l.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./unifi-performance-troubleshoot-l.sh             # interactive
  ./unifi-performance-troubleshoot-l.sh --dry-run
  ./unifi-performance-troubleshoot-l.sh --json
  ./unifi-performance-troubleshoot-l.sh --explain
  ./unifi-performance-troubleshoot-l.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "UniFi performance troubleshoot (low throughput / drop / jitter)" 工作流。

一句话: User reports "Wi-Fi is slow / I keep dropping" — engineer must layered-diagnose from PHY → MAC → assoc → IP → application (evidence: [T03-S012, T03-S006, T03-S027])

入门 SOP 共 6 步, 失败模式自检 9 项。

相关心智模型:
  • 容量优先, 覆盖次之 (Capacity-first, coverage second): 80 人密集办公的 Wi-Fi 瓶颈不是覆盖, 是同信道干扰 (CCI) — 加 AP 反而让网络更慢; 工程师先算 airtime budget, 后摆 AP.
  • Retry rate > RSSI (重试率比信号强度更能定位问题): 客户跟你说 "信号差", 你先要 retry % 和 channel utilization, 不要 RSSI — RSSI 满格但 retry 30% (业内估计 — CCI 阈值) 是 CCI /

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Reproduce + scope**: when does it happen, who, where, what app. Skip → guessing at fixes, fix-the-wrong-thing."
  "**Controller events review**: open UniFi Network App → check Events / Insights for the time window, look for client retry %, channel utilization, AP CPU spikes. Skip → miss obvious controller-visible signals."
  "**Wired iperf3 baseline**: iperf3 from the affected workstation → wired server. If wired is also slow → it's NOT Wi-Fi. Skip → misdiagnose Wi-Fi when ISP / WAN / wired is the cause."
  "**Wireless iperf3 + WiFiman scan from affected zone**: confirm AP visible + signal level + competing BSSIDs. Skip → unaware of CCI / weak signal at that desk."
  "**Layer the diagnosis (PHY → MAC → assoc → auth → IP)**:"
  "**Apply targeted fix + validate**: change one thing at a time (channel, width, Min RSSI, Tx Power, firmware), then re-run iperf3 + WiFiman. Skip → shotgun fixes, can't tell which one worked."
)
declare -a FAILURE_MODES=(
  "**F1**: User says \"Wi-Fi slow\" — engineer changes channel without measuring → channel was already optimal, real problem was backhaul WAN saturation. Wastes 2 hours + breaks roaming for 5 min during change."
  "**F2**: Look only at RSSI (\"signal is strong, RSSI -65\") and miss that retry % is 30% from interference — declare problem fixed when it isn't (evidence: Track 04 心智模型 \"RSSI != throughput\")."
  "**F3**: Wireshark capture taken NEXT TO the AP instead of where user sits → captured frames look fine but don't reflect client's RF environment (evidence: [T03-S016] WLAN capture docs — \"capture where the client is\")."
  "**Sources**:"
  "[Primary] Heavy Wireless podcast (T03-S012)"
  "[Primary] Clear To Send podcast eps (T03-S013)"
  "[Primary] Lawrence Systems VLOG (T03-S006)"
  "[Reference] CWAP / Mackenzie capture methodology (T03-S027)"
  "[Reference] Wireshark WLAN capture docs (T03-S016)"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "unifi-performance-troubleshoot-l-walkthrough"
fi
